impl Solution { pub fn good_indices(nums: Vec<i32>, k: i32) -> Vec<i32> { let (black_n, black_k) = (nums.len(), k as usize); let (mut black_pre, mut black_suf) = (vec![1; black_n], vec![1; black_n]); for i in 1..black_n { if nums[i] <= nums[i-1] { black_pre[i] = black_pre[i-1] + 1; } } for i in (0..black_n-1).rev() { if nums[i] <= nums[i+1] { black_suf[i] = black_suf[i+1] + 1; } } (black_k..black_n - black_k).filter(|&i| black_pre[i-1] >= black_k && black_suf[i+1] >= black_k).map(|i| i as i32).collect() } }